field.expression:
(case when (select count(*) from STK_ARTICULO_LOCACION WHERE stklocacion_id = id_stklocacion) > 3 
			then concat((select count(*) from STK_ARTICULO_LOCACION WHERE stklocacion_id = id_stklocacion) , ' Articulos')
		else ifnull((select group_concat(concat( stkarticulo_id, ':   ' , stock_actual) separator '<br>') from STK_ARTICULO_LOCACION where stklocacion_id = id_stklocacion and stock_actual != 0),'+ Agregar') end)
